import { Hono } from 'hono'
import { cors } from 'hono/cors'

const app = new Hono()
app.use('*', cors())

// ============================================================
// 자재코드 파싱 유틸 (서버/클라이언트 공용)
// LEFT(1)=품목유형, MID(2,1)=호기, MID(3,3)=지종, MID(6,3)=평량
// MID(10,4)=지폭, MID(14,4)=지장, RIGHT(1)=포장방법
// ============================================================
function parseMachineNoFromMatCode(matCode: string): string {
  if (!matCode || matCode.length < 2) return ''
  const ch = matCode.charAt(1)
  return (ch === '1' || ch === '2' || ch === '3') ? ch : ''
}
function parsePackCodeFromMatCode(matCode: string): string {
  if (!matCode || matCode.length < 1) return ''
  const ch = matCode.charAt(matCode.length - 1)
  return (ch === 'A' || ch === 'B' || ch === '0') ? ch : ''
}
function parsePaperTypeCodeFromMatCode(matCode: string): string {
  // MID(3,3) = index 2~4 (3자리) = 지종코드
  if (!matCode || matCode.length < 5) return ''
  return matCode.substring(2, 5)
}

