// 빌드 시 고정되는 버전 태그 (캐시 버스팅용)
const _BUILD_TS = Date.now().toString(36)

app.get('*', (c) => {
  c.header('Cache-Control', 'no-store, no-cache, must-revalidate, max-age=0')
  c.header('Pragma', 'no-cache')
  c.header('Expires', '0')
  c.header('X-Build', _BUILD_TS)
  return c.html(mainHtml)
})

